def _start_scheduler_thread():
    """Start the scheduler in a background thread so API server stays responsive."""
    import threading
    def _run_scheduler():
        try:
            import subprocess
            subprocess.run(["python", "scheduler.py"])
        except Exception as exc:
            logger.error("Scheduler thread failed: %s", exc)
    t = threading.Thread(target=_run_scheduler, daemon=True)
    t.start()
    logger.info("Scheduler started in background thread")




# ---------- Auto-Trade Loop ----------
_auto_trade_active = False
_auto_trade_config = {
    "min_ev": 5.0,       # Minimum theo EV to trade
    "min_kelly": 2.0,    # Minimum kelly %
    "max_size": 10,      # Max USDC per order
    "max_trades_per_cycle": 5,  # Allow more high-EV YES trades per cycle
    "paper_mode": True,   # Start in paper mode for safety
}
_paper_trades = []
_traded_tokens = set()
_trade_cycle_log = []  # Debug: last N cycle summaries  # Track token_ids we already have orders on

def _run_auto_trade_cycle():
    """Execute one auto-trade cycle: get signals, filter, place orders."""
    global _paper_trades
    cfg = _auto_trade_config
    if not _auto_trade_active:
        return
    try:
        _trade_cycle_log.append({"ts": datetime.now(timezone.utc).isoformat(), "status": "cycle_entry", "active": _auto_trade_active})
        if len(_trade_cycle_log) > 30: _trade_cycle_log.pop(0)
        # ── Auto-scan: refresh markets if empty or stale (>5 min) ────
        wm = _state.get("weather_markets", [])
        _last = _state.get("last_scan")
        _stale = True
        if _last:
            try:
                from datetime import datetime, timezone
                _age = (datetime.now(timezone.utc) - datetime.fromisoformat(_last)).total_seconds()
                _stale = _age > 300  # 5 minutes
            except Exception:
                _stale = True
        if (not wm or _stale) and HAS_GAMMA:
            try:
                raw = _gamma_get_markets()
                _state["markets_cache"] = raw
                weather = []
                for m in raw:
                    _tokens = m.get("tokens", [])
                    _yes_p = 0.0
                    _no_p = 0.0
                    for _t in _tokens:
                        _out = str(_t.get("outcome", "")).lower()
                        _pr = float(_t.get("price", 0) or 0)
                        if _out == "yes":
                            _yes_p = _pr
                        elif _out == "no":
                            _no_p = _pr
                    weather.append({
                        "slug": m.get("slug", m.get("market_slug", "")),
                        "question": m.get("question", m.get("category", "")),
                        "city": m.get("city", ""),
                        "station": m.get("station", ""),
                        "category": m.get("category", ""),
                        "outcomes": m.get("outcomes", []),
                        "active": m.get("active", True),
                        "end_date": m.get("end_date_iso", m.get("resolution_time", "")),
                        "prices": m.get("prices", {}),
                        "tokens": _tokens,
                        "confidence": m.get("confidence", 0),
                        "yes_price": _yes_p,
                        "no_price": _no_p,
                        "best_side": "YES" if _yes_p < _no_p else "NO",
                        "best_edge": abs(_yes_p - _no_p) if (_yes_p + _no_p) > 0 else 0,
                        "theoretical_full_ev": 0,
                        "regime": m.get("category", ""),
                    })
                _state["weather_markets"] = weather
                _state["last_scan"] = datetime.now(timezone.utc).isoformat()
                wm = weather
                logger.info("Auto-scan: refreshed %d weather markets", len(wm))
            except Exception as _scan_err:
                logger.warning("Auto-scan failed: %s", _scan_err)
        wx_cities = _weather_cache["data"].get("cities", []) if _weather_cache["data"] else []
        sigs = _build_signals(wm, wx_cities)
        if not sigs:
            _trade_cycle_log.append({"ts": datetime.now(timezone.utc).isoformat(), "status": "no_signals", "wm": len(wm), "wx": len(wx_cities)})
            if len(_trade_cycle_log) > 20: _trade_cycle_log.pop(0)
            logger.info("Auto-trade: no signals (wm=%d wx=%d)", len(wm), len(wx_cities))
            return
        # Agent 7: Weather Sentinel - poll METAR and enrich signals
        if RUFLO_AVAILABLE:
            try:
                if _ruflo_sentinel.needs_poll():
                    _ruflo_sentinel.poll()
                _ruflo_sentinel.enrich_signals(sigs)
                _ruflo_coordinator.report_agent_status('sentinel', True)
                # Sentinel -> SharedState
                try:
                    _ss_states = _ruflo_sentinel.get_all_states()
                    _ruflo_shared.publish('sentinel', 'all_states', _ss_states)
                    _ruflo_shared.publish('sentinel', 'high_confidence', _ruflo_sentinel.get_high_confidence_cities())
                    for _sid, _st in _ss_states.items():
                        if _st.get('age_min', 999) > 120:
                            _ruflo_shared.emit('sentinel', 'station_stale', {'station': _sid, 'age_min': _st.get('age_min')})
                        _rate = abs(_st.get('rate_f_hr', 0))
                        if _rate > 2.0:
                            _ruflo_shared.boost_city_priority('sentinel', _st.get('city', ''), _rate * 2, f'fast_trend_{_rate:.1f}F/hr')
                except Exception:
                    pass
            except Exception as e:
                logger.warning("Sentinel enrich failed: %s", e)
                _ruflo_coordinator.report_agent_status('sentinel', False, e)

        # Agent 8: AccuracyTracker - log predictions and check resolutions
        if RUFLO_AVAILABLE:
            try:
                _ruflo_accuracy.log_predictions(sigs, _ruflo_sentinel)
                if _ruflo_accuracy.needs_resolution_check():
                    _ruflo_accuracy.check_resolutions()
                _ruflo_coordinator.report_agent_status('accuracy_tracker', True)
                # AccuracyTracker -> SharedState
                try:
                    _ss_report = _ruflo_accuracy.get_accuracy_report()
                    _ss_ranks = _ss_report.get('station_rankings', [])
                    _ruflo_shared.publish('accuracy_tracker', 'report', _ss_report)
                    _ruflo_shared.publish('accuracy_tracker', 'unreliable_stations',
                        [s['station_id'] for s in _ss_ranks if s.get('brier_score', 1) > 0.4])
                    _ruflo_shared.publish('accuracy_tracker', 'excellent_stations',
                        [s['station_id'] for s in _ss_ranks if s.get('brier_score', 1) < 0.15])
                    for _sr in _ss_ranks:
                        _ruflo_shared.update_station_reputation(_sr.get('station_id', ''), brier=_sr.get('brier_score'))
                except Exception:
                    pass
            except Exception as e:
                logger.warning("AccuracyTracker cycle failed: %s", e)
                _ruflo_coordinator.report_agent_status('accuracy_tracker', False, e)

        # Agent 9: IntelligenceFeed - Phase 3 enrichment (dynamic sigma, consensus, alerts)
        if RUFLO_AVAILABLE:
            try:
                _ruflo_intel.enrich_signals_phase3(sigs, _ruflo_sentinel, _ruflo_accuracy)
                _ruflo_coordinator.report_agent_status('intelligence_feed', True)
                # IntelligenceFeed -> SharedState
                try:
                    _ss_consensus = _ruflo_intel._consensus_cache
                    _ruflo_shared.publish('intelligence_feed', 'consensus', _ss_consensus)
                    _ruflo_shared.publish('intelligence_feed', 'sigma_adjustments', _ruflo_intel._sigma_adjustments)
                    _ruflo_shared.publish('intelligence_feed', 'alerts', _ruflo_intel._alerts_cache)
                    for _cc, _cd in _ss_consensus.items():
                        if _cd.get('agreement') == 'divergent':
                            _ruflo_shared.emit('intelligence_feed', 'consensus_divergent', {'city': _cc, 'spread': _cd.get('spread_c', 0)})
                        elif _cd.get('agreement') == 'strong':
                            _ruflo_shared.boost_city_priority('intelligence_feed', _cc, 10, 'strong_consensus')
                except Exception:
                    pass
            except Exception as e:
                logger.warning("IntelligenceFeed cycle failed: %s", e)
                _ruflo_coordinator.report_agent_status('intelligence_feed', False, e)

        # Agent 10: RufloCoordinator - cross-agent evaluation and unified decisions
        if RUFLO_AVAILABLE:
            try:
                _ruflo_coordinator.evaluate(sigs, _ruflo_analyst)
                _ruflo_coordinator.report_agent_status('coordinator', True)
                # Coordinator -> SharedState
                try:
                    _ruflo_shared.publish('coordinator', 'decisions', _ruflo_coordinator._decision_log[-20:])
                    _ruflo_shared.publish('coordinator', 'conviction_stats', _ruflo_coordinator._conviction_stats)
                    _ruflo_shared.publish('coordinator', 'cooldowns', {
                        c: cd for c, cd in _ruflo_coordinator._city_cooldowns.items()
                        if time.time() < cd.get('until', 0)
                    })
                    # Coordinator reads stale station events and logs insight
                    _ss_stale = _ruflo_shared.get_events('station_stale', since_ts=time.time()-600)
                    if len(_ss_stale) >= 3:
                        _ruflo_shared.add_strategy_insight('coordinator', f'{len(_ss_stale)} stations stale this cycle - data quality degraded')
                    # Read priority cities and log
                    _ss_prio = _ruflo_shared.get_priority_cities()
                    if _ss_prio:
                        _ruflo_shared.publish('coordinator', 'priority_cities', _ss_prio)
                except Exception:
                    pass
            except Exception as e:
                logger.warning("Coordinator evaluate failed: %s", e)
                _ruflo_coordinator.report_agent_status('coordinator', False, e)

        # SharedState: record cycle completion
        if RUFLO_AVAILABLE:
            try:
                _ruflo_shared.record_cycle()
            except Exception:
                pass

        # Filter for tradeable signals
        tradeable = [s for s in sigs 
                     if s.get("theo_ev", 0) >= cfg["min_ev"]
                     and s.get("kelly", 0) >= cfg["min_kelly"]
                     and s.get("signal") in ("BUY YES", "BUY NO")
                     and s.get("tokens")
                     and s.get("coordinator_verdict", "trade") not in ("veto", "cooldown")]
        tradeable.sort(key=lambda s: s["theo_ev"], reverse=True)
        _trade_cycle_log.append({"ts": datetime.now(timezone.utc).isoformat(), "status": "running", "sigs": len(sigs), "tradeable": len(tradeable), "wm": len(wm)})
        if len(_trade_cycle_log) > 20: _trade_cycle_log.pop(0)
        logger.info("Auto-trade: %d signals -> %d tradeable (ev>=%s kelly>=%s)", len(sigs), len(tradeable), cfg["min_ev"], cfg["min_kelly"])
        if tradeable:
            logger.info("Auto-trade top3: %s", [(s.get('city',''), round(s.get('theo_ev',0),1), s.get('coordinator_verdict','')) for s in tradeable[:3]])
        # Ruflo Agent 4: re-rank by edge*confidence from MarketScanner
        if RUFLO_AVAILABLE and tradeable:
            try:
                _ruflo_ranked = _ruflo_scanner.scan()
                if _ruflo_ranked:
                    def _ruflo_score(s):
                        city = s.get('city', '').lower()
                        for r in _ruflo_ranked:
                            if r.get('city', '').lower() == city:
                                return float(r.get('score', 0))
                        return 0.0
                    tradeable.sort(key=lambda s: (_ruflo_score(s), s.get('theo_ev', 0)), reverse=True)
                    logger.info("RUFLO_AGENT4: re-ranked %d signals. Top city: %s",
                                len(tradeable), tradeable[0].get('city', '?'))
            except Exception as _re4:
                logger.debug("Ruflo Agent4 re-rank error: %s", _re4)
        traded = 0
        for sig in tradeable:
            tokens = sig.get("tokens", [])
            sig_type = sig["signal"]
            # Find the right token
            target_outcome = "Yes" if sig_type == "BUY YES" else "No"
            token_id = None
            for tk in tokens:
                if str(tk.get("outcome", "")).lower() == target_outcome.lower():
                    token_id = tk.get("token_id", "")
                    break
            if not token_id:
                continue
            if token_id in _traded_tokens:
                continue  # Already have an order on this token
            # Entry kill switch: skip if physically impossible to reach temperature
            if ACTIVE_TRADER_AVAILABLE:
                _direction = sig.get("direction", "exact")
                _threshold = sig.get("threshold", 0) or 0
                if _direction == "above":
                    _bin_lo, _bin_hi = _threshold, 999.0
                elif _direction == "below":
                    _bin_lo, _bin_hi = 0.0, _threshold
                else:  # exact / between range
                    _bin_lo, _bin_hi = _threshold - 0.9, _threshold + 0.9
                _local_hour = (datetime.now(timezone.utc).hour - 5) % 24
                _ok, _reason = should_enter(sig.get("city", ""), _bin_lo, _bin_hi, _local_hour)
                if not _ok:
                    logger.warning("ENTRY_KILL: %s bin=%.1f-%.1f | %s", sig.get("city",""), _bin_lo, _bin_hi, _reason)
                    continue
            # Ruflo Agent 1: PreTradeValidator Ã¢ÂÂ hard quality gate
            if RUFLO_AVAILABLE:
                _ruflo_sig = {
                    'confidence': sig.get('confidence', 0),
                    'theo_ev': sig.get('theo_ev', 0),
                    'ev': sig.get('theo_ev', 0),
                    'end_date': sig.get('end_date', ''),
                    'size': cfg['max_size'],
                }
                _v_ok, _v_reason = _ruflo_validator.validate(_ruflo_sig)
                if not _v_ok:
                    logger.warning("RUFLO_REJECT: %s | %s", sig.get('city', ''), _v_reason)
                    continue
            our_prob = sig.get("our_prob", 50) / 100.0
            mkt_price = sig.get("market_price", 50) / 100.0
            if sig_type == "BUY YES":
                price = round(min(mkt_price + 0.01, our_prob - 0.02), 2)
            else:
                price = round(max(mkt_price - 0.01, our_prob + 0.02), 2)
            price = max(0.01, min(0.99, price))
            # Size = dollars to spend / price = number of shares
            # Polymarket min order is $1, so ensure size * price >= 1
            import math
            _coord_mult = sig.get("coordinator_size_mult", 1.0)
            spend = max(1.0, cfg["max_size"] * _coord_mult)  # coordinator-adjusted size
            size = math.ceil(spend / price)
            size = max(1, size)
            trade_info = {
                "ts": datetime.now(timezone.utc).isoformat(),
                "question": sig.get("question", "")[:80],
                "city": sig.get("city", ""),
                "signal": sig_type,
                "token_id": token_id[:12] + "...",
                "price": price, "size": size,
                "ev": sig.get("theo_ev", 0),
                "kelly": sig.get("kelly", 0),
                "our_prob": sig.get("our_prob", 0),
                "mkt_price": sig.get("market_price", 0),
            }
            if cfg["paper_mode"]:
                trade_info["mode"] = "PAPER"
                _traded_tokens.add(token_id)
                _paper_trades.append(trade_info)
                if len(_paper_trades) > 200:
                    _paper_trades = _paper_trades[-200:]
                _trade_log.append(trade_info)
                if len(_trade_log) > _MAX_TRADE_LOG:
                    _trade_log[:] = _trade_log[-_MAX_TRADE_LOG:]
                logger.info("PAPER TRADE: %s %s @ %.2f x %.1f (EV=%.1f)", sig_type, sig.get("city",""), price, size, sig.get("theo_ev",0))
                # Ruflo Agent 3: record outcome for win-rate analytics
                if RUFLO_AVAILABLE:
                    _ruflo_analyst.record(
                        {'question': sig.get('question',''), 'price': price, 'size': size,
                         'ev': sig.get('theo_ev', 0), 'city': sig.get('city','')},
                        {'won': None, 'pnl': 0})
                traded += 1
                if traded >= cfg["max_trades_per_cycle"]:
                    break
            else:
                # LIVE trading
                if not _clob_client:
                    logger.warning("Auto-trade: CLOB client not connected, skipping")
                    continue
                try:
                    from py_clob_client.order_builder.constants import BUY
                    from py_clob_client.clob_types import OrderArgs
                    order_args = OrderArgs(
                        price=price,
                        size=size,
                        side=BUY,
                        token_id=token_id,
                    )
                    resp = _clob_client.create_and_post_order(order_args)
                    trade_info["mode"] = "LIVE"
                    trade_info["response"] = str(resp)[:200]
                    trade_info["token_id"] = token_id
                    _traded_tokens.add(token_id)
                    _trade_log.append(trade_info)
                    if len(_trade_log) > _MAX_TRADE_LOG:
                        _trade_log[:] = _trade_log[-_MAX_TRADE_LOG:]
                    logger.info("LIVE TRADE: %s %s @ %.2f x %.1f => %s", sig_type, sig.get("city",""), price, size, str(resp)[:100])
                    # Ruflo Agent 3: record live trade for analytics
                    if RUFLO_AVAILABLE:
                        _ruflo_analyst.record(
                            {'question': sig.get('question',''), 'price': price, 'size': size,
                             'ev': sig.get('theo_ev', 0), 'city': sig.get('city','')},
                            {'won': None, 'pnl': 0})
                    traded += 1
                    if traded >= cfg["max_trades_per_cycle"]:
                        break
                except Exception as exc:
                    logger.error("Trade failed for %s: %s", sig.get("city",""), exc)
                    trade_info["mode"] = "FAILED"
                    trade_info["error"] = str(exc)[:200]
                    _trade_log.append(trade_info)
        # ââ Agent 5: NO Harvester âââââââââââââââââââââââââââââââââââââââââââââ
        if RUFLO_AVAILABLE and sigs:
            try:
                no_opps = _ruflo_no_harvester.scan(sigs)
                no_traded = 0
                for _no_opp in no_opps:
                    if no_traded >= 5:
                        break
                    _no_tok = _no_opp.get('no_token_id', '')
                    if not _no_tok or _no_tok in _traded_tokens:
                        continue
                    _no_px  = _no_opp['no_price']
                    _no_sz  = _no_opp['size']
                    _city   = _no_opp['city']
                    _exp    = _no_opp['expected_return_pct']
                    _oprob  = _no_opp['our_prob']
                    if cfg.get('paper_mode', True):
                        _paper_trades.append({
                            'token_id': _no_tok,
                            'side': 'BUY',
                            'price': _no_px,
                            'size': _no_sz,
                            'timestamp': time.time(),
                            'signal': 'NO_HARVEST',
                            'city': _city,
                        })
                        _trade_log.append(f"RUFLO_NO_HARVEST PAPER: {_city} | NO @ {_no_px:.3f} | expected +{_exp:.1f}% | our_prob={_oprob:.1f}%")
                        logger.info("RUFLO_NO_HARVEST PAPER: %s | NO @ %.3f | expected +%.1f%% | our_prob=%.1f%%",
                                    _city, _no_px, _exp, _oprob)
                    else:
                        try:
                            _no_order = _clob_client.create_and_post_order(OrderArgs(
                                price=_no_px, size=_no_sz, side=BUY, token_id=_no_tok
                            ))
                            _traded_tokens.add(_no_tok)
                            _trade_log.append(f"RUFLO_NO_HARVEST LIVE: {_city} | NO @ {_no_px:.3f} | expected +{_exp:.1f}%")
                            logger.info("RUFLO_NO_HARVEST LIVE: %s | NO @ %.3f | expected +%.1f%% | order=%s",
                                        _city, _no_px, _exp, _no_order)
                        except Exception as _no_err:
                            logger.error("RUFLO_NO_HARVEST order error %s: %s", _city, _no_err)
                    _traded_tokens.add(_no_tok)
                    no_traded += 1
                    traded += 1
            except Exception as _noh_err:
                logger.error("RUFLO_NO_HARVEST scan error: %s", _noh_err)

        # ââ Agent 6: YES Harvester ââââââââââââââââââââââââââââââââââââââââââââ
        if RUFLO_AVAILABLE and sigs:
            try:
                yes_opps = _ruflo_yes_harvester.scan(sigs)
                yes_h_traded = 0
                for _yes_opp in yes_opps:
                    if yes_h_traded >= 5:
                        break
                    _yes_tok = _yes_opp.get('yes_token_id', '')
                    if not _yes_tok or _yes_tok in _traded_tokens:
                        continue
                    _yes_px  = _yes_opp['yes_price']
                    _yes_sz  = _yes_opp['size']
                    _city    = _yes_opp['city']
                    _exp     = _yes_opp['expected_return_pct']
                    _oprob   = _yes_opp['our_prob']
                    if cfg.get('paper_mode', True):
                        _paper_trades.append({
                            'token_id': _yes_tok,
                            'side': 'BUY',
                            'price': _yes_px,
                            'size': _yes_sz,
                            'timestamp': time.time(),
                            'signal': 'YES_HARVEST',
                            'city': _city,
                        })
                        _trade_log.append(f"RUFLO_YES_HARVEST PAPER: {_city} | YES @ {_yes_px:.3f} | expected +{_exp:.1f}% | our_prob={_oprob:.1f}%")
                        logger.info("RUFLO_YES_HARVEST PAPER: %s | YES @ %.3f | expected +%.1f%% | our_prob=%.1f%%",
                                    _city, _yes_px, _exp, _oprob)
                    else:
                        try:
                            _yes_order = _clob_client.create_and_post_order(OrderArgs(
                                price=_yes_px, size=_yes_sz, side=BUY, token_id=_yes_tok
                            ))
                            _traded_tokens.add(_yes_tok)
                            _trade_log.append(f"RUFLO_YES_HARVEST LIVE: {_city} | YES @ {_yes_px:.3f} | expected +{_exp:.1f}%")
                            logger.info("RUFLO_YES_HARVEST LIVE: %s | YES @ %.3f | expected +%.1f%% | order=%s",
                                        _city, _yes_px, _exp, _yes_order)
                        except Exception as _yes_err:
                            logger.error("RUFLO_YES_HARVEST order error %s: %s", _city, _yes_err)
                    _traded_tokens.add(_yes_tok)
                    yes_h_traded += 1
                    traded += 1
            except Exception as _yh_err:
                logger.error("RUFLO_YES_HARVEST scan error: %s", _yh_err)


        # ── Agent 11 & 12: Exit Strategy (ProfitTaker + RiskCutter) ──────
        if RUFLO_AVAILABLE and _paper_trades:
            try:
                # Register any new BUY positions with ProfitTaker
                for pt in _paper_trades:
                    tid = pt.get('token_id', '')
                    if tid and tid not in _profit_taker.get_positions():
                        _profit_taker.register_position(
                            token_id=tid,
                            entry_price=pt.get('price', 0) * 100,  # convert to cents
                            size=pt.get('size', 1) * pt.get('price', 0.05),
                            city=pt.get('city', ''),
                            bin_label=pt.get('signal', ''),
                            confidence='MED',
                            signal_type=pt.get('signal', 'BUY YES'),
                            question=pt.get('question', ''),
                        )

                # Update prices from current market data (use signal prices)
                price_map = {}
                for s in sigs:
                    tid_y = s.get('yes_token_id', '')
                    tid_n = s.get('no_token_id', '')
                    mp = s.get('market_price', 0)
                    if tid_y and mp > 0:
                        price_map[tid_y] = mp  # cents
                    if tid_n and mp > 0:
                        price_map[tid_n] = 100 - mp
                if price_map:
                    _profit_taker.update_prices(price_map)

                # Calculate hours to resolution (midnight UTC)
                from datetime import datetime, timezone
                now_utc = datetime.now(timezone.utc)
                midnight = now_utc.replace(hour=0, minute=0, second=0, microsecond=0)
                if now_utc.hour >= 0:
                    from datetime import timedelta
                    midnight = midnight + timedelta(days=1)
                hours_left = (midnight - now_utc).total_seconds() / 3600.0

                # Build sentinel data for RiskCutter
                sentinel_wx = {}
                if _ruflo_sentinel:
                    for city_name, station_id in _ruflo_sentinel.CITY_TO_STATION.items():
                        trend = _ruflo_sentinel._trends.get(station_id, {})
                        if trend.get('current_f') is not None:
                            sentinel_wx[city_name] = {
                                'current_f': trend['current_f'],
                                'trend_rate_f_hr': trend.get('rate_f_hr', 0),
                            }

                # Run ProfitTaker evaluation
                profit_signals = _profit_taker.evaluate(
                    hours_to_resolution=hours_left
                )

                # Run RiskCutter evaluation
                cut_signals = _risk_cutter.evaluate(
                    positions=_profit_taker.get_positions(),
                    hours_to_resolution=hours_left,
                    sentinel_data=sentinel_wx,
                    profit_taker_signals=profit_signals,
                )

                # Combine all sell signals
                all_sells = profit_signals + cut_signals
                for sell in all_sells:
                    sell_info = {
                        'ts': datetime.now(timezone.utc).isoformat(),
                        'action': 'SELL',
                        'reason': sell.get('reason', ''),
                        'token_id': sell.get('token_id', '')[:12] + '...',
                        'city': sell.get('city', ''),
                        'entry_price': sell.get('entry_price', 0),
                        'current_price': sell.get('current_price', 0),
                        'sell_size': sell.get('sell_size', 0),
                        'urgency': sell.get('urgency', ''),
                        'mode': 'PAPER' if cfg['paper_mode'] else 'LIVE',
                    }
                    _paper_trades.append(sell_info)
                    _trade_log.append(sell_info)
                    logger.info("EXIT %s: %s %s | %s | entry=%.1fc curr=%.1fc | %s",
                                sell_info['mode'], sell.get('reason',''), sell.get('city',''),
                                sell.get('bin',''), sell.get('entry_price',0),
                                sell.get('current_price',0), sell.get('urgency',''))

                    # Remove fully-exited positions
                    if sell.get('sell_fraction', 1.0) >= 1.0:
                        _profit_taker.remove_position(sell.get('token_id', ''))

                if all_sells:
                    logger.info("EXIT AGENTS: %d profit signals, %d risk cuts, %d total sells",
                                len(profit_signals), len(cut_signals), len(all_sells))
            except Exception as _exit_err:
                logger.error("EXIT AGENTS error: %s", _exit_err)

        logger.info("Auto-trade: placed %d paper trades this cycle", traded)
        logger.info("Auto-trade cycle done: %d trades placed (%s mode)", traded, "PAPER" if cfg["paper_mode"] else "LIVE")
    except Exception as exc:
        _trade_cycle_log.append({"ts": datetime.now(timezone.utc).isoformat(), "status": "ERROR", "error": str(exc)})
        if len(_trade_cycle_log) > 30: _trade_cycle_log.pop(0)
        logger.error("Auto-trade cycle error: %s", exc)


def _start_auto_trade_timer():
    """Run auto-trade cycle every 5 minutes in background thread."""
    import threading
    def _loop():
        while True:
            try:
                if _auto_trade_active:
                    _run_auto_trade_cycle()
            except Exception as _thread_err:
                logger.error("Auto-trade THREAD error: %s", _thread_err)
                _trade_cycle_log.append({"ts": datetime.now(timezone.utc).isoformat(), "status": "THREAD_ERROR", "error": str(_thread_err)})
                if len(_trade_cycle_log) > 30: _trade_cycle_log.pop(0)
            time.sleep(60)  # 1 minute
    t = threading.Thread(target=_loop, daemon=True)
    t.start()
    logger.info("Auto-trade timer started (every 1 min)")


@app.route("/api/bot/start", methods=["POST"])
def start_bot():
    """Start the auto-trade bot. Body: {mode: 'paper'|'live', min_ev, max_size}"""
    global _auto_trade_active
    data = request.get_json(force=True) if request.data else {}
    mode = data.get("mode", "paper").lower()
    _auto_trade_config["paper_mode"] = mode != "live"
    if "min_ev" in data:
        _auto_trade_config["min_ev"] = float(data["min_ev"])
    if "max_size" in data:
        _auto_trade_config["max_size"] = float(data["max_size"])
    if "min_kelly" in data:
        _auto_trade_config["min_kelly"] = float(data["min_kelly"])
    if "max_trades_per_cycle" in data:
        _auto_trade_config["max_trades_per_cycle"] = int(data["max_trades_per_cycle"])
    _auto_trade_active = True
    # Run first cycle immediately
    import threading
    threading.Thread(target=_run_auto_trade_cycle, daemon=True).start()
    _log(f"Bot started in {mode.upper()} mode (min_ev={_auto_trade_config['min_ev']}, max_size={_auto_trade_config['max_size']})")
    return jsonify({"ok": True, "mode": mode, "config": _auto_trade_config, "status": "RUNNING"})


@app.route("/api/bot/stop", methods=["POST"])
def stop_bot():
    """Stop the auto-trade bot."""
    global _auto_trade_active
    _auto_trade_active = False
    _log("Bot stopped")
    return jsonify({"ok": True, "status": "STOPPED"})


