@app.route("/api/entry-check")
def entry_check():
    """Check entry kill switch. Query: city, bin_lo, bin_hi"""
    city = request.args.get("city", "")
    try:
        bin_lo = float(request.args.get("bin_lo", 0))
        bin_hi = float(request.args.get("bin_hi", 999))
    except ValueError:
        return jsonify({"error": "bin_lo and bin_hi must be numbers"}), 400
    local_hour = (datetime.now(timezone.utc).hour - 5) % 24
    ok, reason = should_enter(city, bin_lo, bin_hi, local_hour)
    obs_temp = None
    try:
        import active_trader as _at
        obs_temp = _at.get_obs_temp_f(city)
    except Exception:
        pass
    return jsonify({
        "city": city, "bin_lo": bin_lo, "bin_hi": bin_hi,
        "ok": ok, "reason": reason,
        "obs_temp": obs_temp, "local_hour": local_hour,
    })


